mapper.select:
select YYYY, SEL_CODE, SITE as SITE_ORG, CASE WHEN SITE='HQ' Then '본사' WHEN SITE='VN' then 'VINA' else site end as SITE, ACCT_CLASS as ACCT_CLASS_ORG, CASE WHEN ACCT_CLASS='AA' Then '가공비' WHEN ACCT_CLASS='BB' then '개발비' WHEN ACCT_CLASS='CC' then '판매관리비' else ACCT_CLASS end as ACCT_CLASS, 계정과목내부코드, 전표기표여부, ACCT, ACCT_NAME, 차대, 계정대분류, 관리항목유형, 계정과목Lev AS ACCT_LEV, 상위계정과목, 상위계정과목내부코드, 소분류, 중분류, 대분류, EXPEN_SEL, EXPEN_SEL명 AS EXPEN_SEL_NAME FROM doi_acct where 1=1
and yyyy = #{yyyy}
and site = #{site}
order BY acct ;

